'use server'

import { refresh } from 'next/cache'
import { cookies } from 'next/headers'

const NOTIFICATION_PREFERENCE_COOKIE = 'notifications-enabled'

/** Toggle the signed-in user's notification preference and refresh this route. */
export async function toggleNotificationPreference() {
  const cookieStore = await cookies()
  const currentlyEnabled = cookieStore.get(NOTIFICATION_PREFERENCE_COOKIE)?.value !== 'false'

  cookieStore.set(NOTIFICATION_PREFERENCE_COOKIE, String(!currentlyEnabled), {
    httpOnly: true,
    sameSite: 'lax',
    path: '/',
  })

  // refresh() updates the current route's Server Component tree in place.
  // It deliberately does not navigate or redirect to another page.
  refresh()
}

