import { cookies } from 'next/headers'

import { toggleNotificationPreference } from './actions'

const NOTIFICATION_PREFERENCE_COOKIE = 'notifications-enabled'

export default async function Home() {
  const cookieStore = await cookies()
  const notificationsEnabled =
    cookieStore.get(NOTIFICATION_PREFERENCE_COOKIE)?.value !== 'false'

  return (
    <main>
      <h1>Settings</h1>
      <section aria-labelledby="notification-heading">
        <h2 id="notification-heading">Notifications</h2>
        <p>
          Status:{' '}
          <strong>{notificationsEnabled ? 'On' : 'Off'}</strong>
        </p>
        <form action={toggleNotificationPreference}>
          <button type="submit">
            Turn notifications {notificationsEnabled ? 'off' : 'on'}
          </button>
        </form>
      </section>
    </main>
  )
}

